import React, { useState, useEffect } from "react";
import axios from "axios";
import { FaLock } from "react-icons/fa";
import { useNavigate } from "react-router-dom";
import styles from "./resetpassword.module.css";

const ResetPassword = () => {
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const navigate = useNavigate();
  const userEmail = localStorage.getItem("resetEmail");
  const otpVerified = localStorage.getItem("otpVerified");
  const otpToken = localStorage.getItem("otpToken");

  useEffect(() => {
    if (!userEmail || otpVerified !== "true") {
      navigate("/forgot-password");
    }
  }, [navigate, userEmail, otpVerified]);

  const handleResetPassword = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    if (!password || !confirmPassword) {
      setError("All fields are required.");
      return;
    }
    if (password !== confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    if (!otpToken) {
      setError("OTP verification required. Please restart the process.");
      return;
    }

    try {
      setIsSubmitting(true);
      const response = await axios.post(
        "http://localhost:5000/api/auth/reset-password",
        { email: userEmail, password, otpToken }
      );

      if (response.data?.success) {
        setMessage("Password successfully reset! Redirecting to login...");
        localStorage.removeItem("resetEmail");
        localStorage.removeItem("otpVerified");
        localStorage.removeItem("otpToken");
        setTimeout(() => navigate("/"), 2000);
      } else {
        setError(response.data.message || "Error resetting password.");
      }
    } catch (err) {
      setError(err.response?.data?.message || "Server error. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className={styles.resetPasswordContainer}>
      <div className={styles.resetPasswordCard}>
        <h2>Reset Password</h2>
        <form onSubmit={handleResetPassword}>
          <input type="password" placeholder="New Password" value={password} onChange={(e) => setPassword(e.target.value)} required />
          <input type="password" placeholder="Confirm Password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} required />
          <button type="submit" disabled={isSubmitting}>{isSubmitting ? "Updating..." : "Update Password"}</button>
          {message && <p className={styles.successMessage}>{message}</p>}
          {error && <p className={styles.errorMessage}>{error}</p>}
        </form>
      </div>
    </div>
  );
};

export default ResetPassword;
